css_variables:
:root {
  /* Colors */
  --color-primary: #8B7355;
  --color-primary-light: #D4C5B2;
  --color-primary-dark: #6B5A42;
  --color-secondary: #D4C5B2;
  --color-accent: #6B8F71;
  --color-accent-light: #8FB896;
  --color-accent-dark: #4A6E50;
  --color-background: #FAF7F2;
  --color-surface: #FFFFFF;
  --color-surface-elevated: #F5F0E8;
  --color-text-primary: #3D3229;
  --color-text-secondary: #716A61;
  --color-text-muted: #A8A29A;
  --color-border: #E5DDD3;
  --color-success: #34D399;
  --color-warning: #FBBF24;
  --color-error: #EF4444;
  --color-info: #60A5FA;

  /* Typography */
  --font-display: 'Space Grotesk', sans-serif;
  --font-body: 'Inter', sans-serif;
  --font-mono: 'JetBrains Mono', monospace;

  /* Spacing */
  --spacing-unit: 8px;

  /* Borders */
  --radius-sm: 0.25rem;
  --radius-md: 0.5rem;
  --radius-lg: 0.75rem;
  --radius-xl: 1rem;
  --radius-full: 9999px;

  /* Transitions */
  --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-base: 300ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-slow: 500ms cubic-bezier(0.4, 0, 0.2, 1);
}
